const items = $input.all();
const seen  = new Set();
const result = [];

for (const item of items) {
  const { website, phone } = item.json;
  const normWeb   = website ? website.toLowerCase().replace(/^https?:\/\/(www\.)?/, '').replace(/\/$/, '') : null;
  const normPhone = phone   ? phone.replace(/[\s\-\.\(\)\+]/g, '') : null;
  const key = normWeb || normPhone;

  if (!key || !seen.has(key)) {
    if (key) seen.add(key);
    result.push(item);
  }
}
return result;

