const claudeItems = $input.all();
const originalItems = $('Build AI Prompt').all();

return claudeItems.map((item, i) => {
  const original = originalItems[i]?.json || {};
  const { ai_prompt, ...leadData } = original;

  let emailData = { subject: '', email_body: '' };
  try {
    const rawText =
      item.json?.content?.[0]?.text ||
      item.json?.body?.content?.[0]?.text || '';
    const match = rawText.match(/\{[\s\S]*?"subject"[\s\S]*?\}/);
    if (match) emailData = JSON.parse(match[0]);
  } catch (e) {
    emailData = { subject: 'Parse error', email_body: '' };
  }

  return {
    json: {
      ...leadData,
      email_subject: emailData.subject   || '',
      email_body:    emailData.email_body || ''
    }
  };
});

