const result = [];
for (const item of items) {
  const existing = item.json.email || '';
  const scraped  = extractEmail(item.json.scrapedHtml);
  const email    = existing || scraped;

  if (!email) continue; // filter out leads with no email

  const { scrapedHtml, ...lead } = item.json;
  result.push({ json: { ...lead, email } });
}
return result;

